    val_html=$(echo "$output" | jq -r '.html')
    assert_not_empty "$val_html" 'html'
    local val_markdown_content
    val_markdown_content=$(echo "$output" | jq -r '.markdown.content')
    assert_not_empty "$val_markdown_content" 'markdown.content'
